function DefaultCurrency227() {}
DefaultCurrency227.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency227.tabIndex = -1;
DefaultCurrency227.maxLength = 1;
DefaultCurrency227.isReadOnly = function(){return true;}
DefaultCurrency227.isTemporary = function(){return true;}
DefaultCurrency227.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency227.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }

